import{_ as t,o as n,c as r,ag as a}from"./chunks/framework.C9sp7nFj.js";const p=JSON.parse('{"title":"微信公众号","description":"","frontmatter":{},"headers":[],"relativePath":"zh/channels/wechatoa.md","filePath":"zh/channels/wechatoa.md","lastUpdated":1777012567000}'),e={name:"zh/channels/wechatoa.md"};function l(s,o,i,g,h,c){return n(),r("div",null,[...o[0]||(o[0]=[a('<h1 id="微信公众号" tabindex="-1">微信公众号 <a class="header-anchor" href="#微信公众号" aria-label="Permalink to &quot;微信公众号&quot;">​</a></h1><p>与 <strong>个人微信扫码</strong> 那套不同：这是 <strong>服务号/公众号的 webhook 接入</strong>，适合平台把消息<strong>推</strong>到你部署的 URL，多用在私聊入站场景。</p><h2 id="_1-准备平台侧信息" tabindex="-1">1. 准备平台侧信息 <a class="header-anchor" href="#_1-准备平台侧信息" aria-label="Permalink to &quot;1. 准备平台侧信息&quot;">​</a></h2><p>在微信公众号平台准备至少：</p><ul><li><strong>App ID</strong></li><li><strong>App Secret</strong></li><li><strong>Token</strong></li></ul><p>若开加密传输，还要 <strong>Encoding AES Key</strong>；出网要绕代理时可能有 <strong>代理 URL</strong> 等，按你部署来。</p><h2 id="_2-在-memoh-里加渠道" tabindex="-1">2. 在 Memoh 里加渠道 <a class="header-anchor" href="#_2-在-memoh-里加渠道" aria-label="Permalink to &quot;2. 在 Memoh 里加渠道&quot;">​</a></h2><ol><li>机器人 <strong>Platforms</strong> → <strong>Add Channel</strong> → <strong>WeChat Official Account</strong>（名称以界面为准）。</li><li>填 <strong>App ID</strong>、<strong>App Secret</strong>、<strong>Token</strong>。</li><li>选 <strong>加解密方式</strong>（与微信后台一致）。</li><li>若用 <code>safe</code> / <code>compatible</code> 等要密钥的模式，再填 <strong>Encoding AES Key</strong>。</li><li>先<strong>保存</strong>渠道。保存后 Memoh 会生成 <strong>URL(服务器配置)</strong> 用的回调地址，复制到微信平台。</li></ol><h2 id="_3-在微信平台填回调" tabindex="-1">3. 在微信平台填回调 <a class="header-anchor" href="#_3-在微信平台填回调" aria-label="Permalink to &quot;3. 在微信平台填回调&quot;">​</a></h2><ol><li>把 Memoh 的 <strong>Webhook 回调 URL</strong> 粘到公众号后台「服务器配置」的 URL。</li><li><strong>Token</strong>、<strong>Encoding</strong>、<strong>EncodingAESKey</strong> 两边必须<strong>完全一致</strong>。</li><li>微信会先做一次<strong>验证</strong>，通过后才真正推消息。</li></ol><h2 id="_4-启用与试发" tabindex="-1">4. 启用与试发 <a class="header-anchor" href="#_4-启用与试发" aria-label="Permalink to &quot;4. 启用与试发&quot;">​</a></h2><ol><li>Memoh 里打开该渠道。</li><li>用测试号或正式号走一条<strong>私聊</strong>入站，看 Memoh 是否收到、机器人能否回。</li></ol><h2 id="支持的能力" tabindex="-1">支持的能力 <a class="header-anchor" href="#支持的能力" aria-label="Permalink to &quot;支持的能力&quot;">​</a></h2><ul><li>私聊场景</li><li>回复</li><li>附件/媒体</li></ul><p><strong>注意</strong>（以当前适配为准）：</p><ul><li>不是群聊那种产品形态</li><li>出站多 <strong>非流式</strong></li></ul>',16)])])}const _=t(e,[["render",l]]);export{p as __pageData,_ as default};
